    const actual = score("street");
    try testing.expectEqual(expected, actual);
}

test "medium, valuable word" {
    const expected: u32 = 22;
    const actual = score("quirky");
    try testing.expectEqual(expected, actual);
}

test "long, mixed-case word" {
    const expected: u32 = 41;
