```zig
const std = @import("std");

pub fn score(s: []const u8) u32 {
    var total: u32 = 0;
    for (s) |c| {
        const upper = std.ascii.toUpper(c);
        const val: u32 = switch (upper) {
            'A', 'E', 'I', 'O', 'U', 'L', 'N', 'R', 'S', 'T' => 1,
            'D', 'G' => 2,
            'B', 'C', 'M', 'P' => 3,
            'F', 'H', 'V', 'W', 'Y' => 4,
            'K' => 5,
            'J', 'X' => 8,
            'Q', 'Z' => 10,
            else => 0,
        };
        total += val;
    }
    return total;
}
